// ECGLine.tsx
import React from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import {useSharedValue, useFrameCallback, useDerivedValue} from 'react-native-reanimated';
function pulseShape(t: number): number { const m = t % 1; if (m < 0.4) return 0; if (m < 0.45) return (m - 0.4) * 20; if (m < 0.5) return 1 - (m - 0.45) * 30; if (m < 0.55) return -0.5 + (m - 0.5) * 20; return 0; }
export function ECGLine({width, height = 100}: {width: number; height?: number}) {
  const t = useSharedValue(0);
  useFrameCallback(({timeSinceFirstFrame}) => { t.value = timeSinceFirstFrame / 1000; });
  const path = useDerivedValue(() => { const p = Skia.Path.Make(); const cy = height / 2; const samples = 200; for (let i = 0; i < samples; i++) { const x = (i / samples) * width; const phase = (t.value - i * 0.005) * 1.2; const y = cy - pulseShape(phase) * (height * 0.4); if (i === 0) p.moveTo(x, y); else p.lineTo(x, y); } return p; });
  return (<View style={{width, height, backgroundColor:'#0A0A0F'}}><Canvas style={StyleSheet.absoluteFill}><Path path={path} style='stroke' strokeWidth={2} color='#FF3B5C' strokeCap='round' strokeJoin='round'/></Canvas></View>);
}

