import React, {useState} from 'react';
import {StyleSheet, View, Text, LayoutChangeEvent} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withRepeat, withSequence, withTiming, withDelay} from 'react-native-reanimated';
export function Marquee({text, width}: {text: string; width: number}) {
  const [textWidth, setTextWidth] = useState(0);
  const tx = useSharedValue(0);
  React.useEffect(() => { if (textWidth > width) { tx.value = withRepeat(withSequence(withDelay(1500, withTiming(width - textWidth - 16, {duration: (textWidth - width) * 30})), withDelay(1500, withTiming(0, {duration: (textWidth - width) * 30}))), -1, false); } else { tx.value = 0; }}, [textWidth, width]);
  const style = useAnimatedStyle(() => ({transform: [{translateX: tx.value}]}));
  return (<View style={[s.wrap, {width}]}><Animated.Text style={[s.text, style]} onLayout={(e: LayoutChangeEvent) => setTextWidth(e.nativeEvent.layout.width)}>{text}</Animated.Text></View>);
}
