import React, {memo, useEffect, useMemo, useState} from 'react';
import {StyleSheet, Text, View} from 'react-native';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import {Easing, useSharedValue, withDelay, withTiming} from 'react-native-reanimated';
type Slice = {label: string; value: number; color: string};
function segmentPath(cx: number, cy: number, r: number, start: number, sweep: number) { const p = Skia.Path.Make(); p.addArc({x: cx-r, y: cy-r, width: r*2, height: r*2}, start, sweep); return p; }
const Segment = memo(function Segment({path, color}: {path: ReturnType<typeof Skia.Path.Make>; color: string}) { return <Path path={path} color={color} style="stroke" strokeWidth={32} strokeCap="round" />; });
export function DonutChart({slices, size = 200}: {slices: Slice[]; size?: number}) {
  const progress = useSharedValue(0);
  const [selected, setSelected] = useState(0);
  useEffect(() => { progress.value = withDelay(80, withTiming(1, {duration: 700, easing: Easing.out(Easing.cubic)})); }, [progress, slices.length]);
  const total = Math.max(1, slices.reduce((a, b) => a + b.value, 0));
  const paths = useMemo(() => { let start = -90; return slices.map((slice) => { const sweep = (slice.value / total) * 360; const path = segmentPath(size/2, size/2, size/2 - 20, start, sweep); start += sweep; return {slice, path}; }); }, [slices, size, total]);
  return <View accessibilityRole="image" accessibilityLabel={slices.map(s => `${s.label} ${s.value}`).join(', ')}><Canvas style={{width: size, height: size}}>{paths.map(({slice, path}) => <Segment key={slice.label} path={path} color={slice.color} />)}</Canvas><View>{slices.map((s, i) => <Text key={s.label} onPress={() => setSelected(i)} style={i === selected ? styles.selected : styles.label}>{s.label}: {s.value}</Text>)}</View></View>;
}
const styles = StyleSheet.create({label: {minHeight: 32}, selected: {minHeight: 32, fontWeight: '700', color: '#0f766e'}});

