// rn-114: gesture with non-gesture fallback for Hold-to-record voice with slide-to-cancel
import React from 'react';
import {Pressable, Text, View} from 'react-native';
import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import Animated, {useAnimatedStyle, useReducedMotion, useSharedValue, withSpring} from 'react-native-reanimated';
export function HoldToRecordVoiceWithSlideToCancelGesture({onCommit}) {
  const reduceMotion = useReducedMotion();
  const x = useSharedValue(0);
  const pan = Gesture.Pan().activeOffsetX([-12,12]).onUpdate(e => { x.value = Math.max(-120, Math.min(120, e.translationX)); }).onEnd(() => { x.value = reduceMotion ? 0 : withSpring(0); });
  const style = useAnimatedStyle(() => ({transform:[{translateX:x.value}]}));
  return <View><GestureDetector gesture={pan}><Animated.View style={style}><Pressable accessibilityRole="button" accessibilityLabel="Hold-to-record voice with slide-to-cancel" accessibilityHint="Use the visible button if gestures are difficult" accessibilityActions={[{name:'activate',label:'Commit'}]} onAccessibilityAction={onCommit} hitSlop={{top:8,right:8,bottom:8,left:8}} style={{minHeight:44,minWidth:44}} onPress={onCommit}><Text>Hold-to-record voice with slide-to-cancel</Text></Pressable></Animated.View></GestureDetector></View>;
}

import React, {useEffect} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Circle, Group} from '@shopify/react-native-skia';
import {Easing, useSharedValue, withRepeat, withTiming} from 'react-native-reanimated';
export function OrbitLoader({size = 48, color = '#0A84FF'}: {size?: number; color?: string}) {
  const phase = useSharedValue(0);
  useEffect(() => { phase.value = withRepeat(withTiming(1, {duration: 900, easing: Easing.linear}), -1, false); }, [phase]);
  const r = size / 3; const cx = size / 2; const cy = size / 2;
  const dots = [0, 1, 2].map((i) => ({x: cx + Math.cos(i * Math.PI * 2 / 3) * r, y: cy + Math.sin(i * Math.PI * 2 / 3) * r, opacity: 0.45 + i * 0.2}));
  return <View style={styles.wrap} accessibilityRole="progressbar" accessibilityLabel="Loading"><Canvas style={{width: size, height: size}}><Group transform={[{rotate: phase.value * Math.PI * 2}, {translateX: cx}, {translateY: cy}]}>{dots.map((dot, i) => <Circle key={i} cx={dot.x - cx} cy={dot.y - cy} r={4 + i} color={color} opacity={dot.opacity} />)}</Group></Canvas></View>;
}
const styles = StyleSheet.create({wrap: {alignItems: 'center', justifyContent: 'center'}});

